    79          Uuid topicId = log.topicId().get();
    80          int partitionId = log.topicPartition().partition();
    81          PartitionRegistration partition = newTopicsImage.getPartition(topicId, partitionId);
    82          if (partition == null) {
    83              LOG.info("Found stray log dir {}: the topicId {} does not exist in the metadata image.", log, topicId);
    84              return true;
    85          } else {
    86              List<Integer> replicas = Arrays.stream(partition.replicas).boxed().toList();
    87              if (!replicas.contains(brokerId)) {
    88                  LOG.info("Found stray log dir {}: the current replica assignment {} does not contain the local brokerId {}.",
    89                          log, replicas.stream().map(String::valueOf).collect(Collectors.joining(", ", "[", "]")), brokerId);
    90                  return true;
    91              } else {
    92                  return false;
    93              }
    94          }
